BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?dep ?client ?clientName ?supplier ?supplierName WHERE {
  <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::APS%2520Requirements%2520Flowdown> vocab:NamedElement_supplierDependency ?dep .
  ?dep vocab:Dependency_client ?client .
  ?dep vocab:Dependency_supplier ?supplier .
  OPTIONAL { ?client vocab:NamedElement_name ?clientName }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName }
}
LIMIT 25

